require "data.Island"

IslandConfig = {}
IslandConfig.Island = {}
IslandConfig.Configs = {}

function IslandConfig:init(config)
    for id, area in pairs(config) do
        local item = {}
        item.id = tonumber(id)
        local spos = StringUtil.split(area.startPos, "#")
        item.startPos = VectorUtil.newVector3(tonumber(spos[1]), tonumber(spos[2]), tonumber(spos[3]))
        local epos = StringUtil.split(area.endPos, "#")
        item.endPos = VectorUtil.newVector3(tonumber(epos[1]), tonumber(epos[2]), tonumber(epos[3]))
        self.Configs[item.id] = item
        self.Island[item.id] = Island.new(item)
    end
end

function IslandConfig:inWhichIsland(pos)
    for id, island in pairs(self.Island) do
        if island:isInArea(pos) then
            return id
        end
    end
    return 0
end

function IslandConfig:randomPos(canSame, ifDesignated)
    local island = self:randomIsland(canSame, ifDesignated)
    if island ~= nil then
        return island:randomPos()
    end
    return self.Island[1]:randomPos()
end

function IslandConfig:getIslandById(id)
    local result = self.Island[tonumber(id)]
    if result == nil then
        result = self.Island[1]
    end
    return result
end

function IslandConfig:randomIsland(canSame, ifDesignated)
    RandomUtil:setRandomSeed()
    local data = {}
    local pool = TableUtil.copyTable(self.Configs)
    for id, island in pairs(pool) do
        if id ~= canSame and (ifDesignated == 0 or ifDesignated == id) then
            table.insert(data, id)
        end
    end
    local remark = "randomPos".. os.time()
    RandomUtil:initRandomSeed(remark, data)
    local index = RandomUtil:get(remark)
    return self.Island[index] or self.Island[1]
end
